package courses

import (
	"encoding/json"
	"log"
	"net/http"
)

type Handlers struct {
	courses CourseQueryService
}

func NewCoursesHandlers(qs CourseQueryService) *Handlers {
	return &Handlers{courses: qs}
}

func (handler *Handlers) GetCoursesHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	cursor := r.URL.Query().Get("cursor")
	keyword := r.URL.Query().Get("keyword")

	courses, err := handler.courses.FindCourses(r.Context(), keyword, cursor)
	if err != nil {
		log.Printf("FindCourses error: %v", err)
		w.WriteHeader(http.StatusInternalServerError)
		json.NewEncoder(w).Encode(map[string]string{"error": "InternalServerError"})
		return
	}

	json.NewEncoder(w).Encode(courses)
}

